#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

inline int maximum(int a, int b, int c)
{
    int k = (a <= b) ? b : a;
    return (k <= c) ? c : k;
}

inline void compute_tile(__global int *reference,
                         __global int *input_itemsets,
                         __local int *itemsets_l,
                         __local int *reference_l,
                         int max_cols,
                         int penalty,
                         int row_block,
                         int col_block)
{
    int tx = (int)get_local_id(0);

    for (int idx = tx; idx < BLOCK_SIZE * BLOCK_SIZE; idx += BLOCK_SIZE) {
        int i = idx / BLOCK_SIZE;
        int j = idx % BLOCK_SIZE;
        reference_l[idx] =
            reference[max_cols * (row_block * BLOCK_SIZE + i + 1) +
                      (col_block * BLOCK_SIZE + j + 1)];
    }

    for (int idx = tx; idx < (BLOCK_SIZE + 1) * (BLOCK_SIZE + 1); idx += BLOCK_SIZE) {
        int i = idx / (BLOCK_SIZE + 1);
        int j = idx % (BLOCK_SIZE + 1);
        itemsets_l[idx] =
            input_itemsets[max_cols * (row_block * BLOCK_SIZE + i) +
                           (col_block * BLOCK_SIZE + j)];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int s = 2; s <= 2 * BLOCK_SIZE; s++) {
        int start_i = (s > BLOCK_SIZE) ? (s - BLOCK_SIZE) : 1;
        int end_i = ((s - 1) < BLOCK_SIZE) ? (s - 1) : BLOCK_SIZE;
        int count = end_i - start_i + 1;

        if (tx < count) {
            int i = start_i + tx;
            int j = s - i;
            int idx = i * (BLOCK_SIZE + 1) + j;

            int nw = itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + (j - 1)] +
                     reference_l[(i - 1) * BLOCK_SIZE + (j - 1)];
            int w = itemsets_l[i * (BLOCK_SIZE + 1) + (j - 1)] - penalty;
            int n = itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty;

            itemsets_l[idx] = maximum(nw, w, n);
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int idx = tx; idx < BLOCK_SIZE * BLOCK_SIZE; idx += BLOCK_SIZE) {
        int i = idx / BLOCK_SIZE;
        int j = idx % BLOCK_SIZE;
        input_itemsets[max_cols * (row_block * BLOCK_SIZE + i + 1) +
                       (col_block * BLOCK_SIZE + j + 1)] =
            itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + (j + 1)];
    }
}

__kernel void nw_kernel1(__global int *reference,
                         __global int *input_itemsets,
                         __global int *output_itemsets,
                         __local int *itemsets_l,
                         __local int *reference_l,
                         int max_cols,
                         int penalty,
                         int blk,
                         int block_width,
                         int worksize,
                         int offset_r,
                         int offset_c)
{
    (void)output_itemsets;
    (void)block_width;
    (void)worksize;
    (void)offset_r;
    (void)offset_c;

    int bx = (int)get_group_id(0);
    int row_block = blk - 1 - bx;
    int col_block = bx;

    compute_tile(reference, input_itemsets, itemsets_l, reference_l,
                 max_cols, penalty, row_block, col_block);
}

__kernel void nw_kernel2(__global int *reference,
                         __global int *input_itemsets,
                         __global int *output_itemsets,
                         __local int *itemsets_l,
                         __local int *reference_l,
                         int max_cols,
                         int penalty,
                         int blk,
                         int block_width,
                         int worksize,
                         int offset_r,
                         int offset_c)
{
    (void)output_itemsets;
    (void)worksize;
    (void)offset_r;
    (void)offset_c;

    int bx = (int)get_group_id(0);
    int row_block = block_width - 1 - bx;
    int col_block = block_width - blk + bx;

    compute_tile(reference, input_itemsets, itemsets_l, reference_l,
                 max_cols, penalty, row_block, col_block);
}
